 1	import React, { FC, useState } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import DataImportCronModel from '@kubevirt-ui/kubevirt-api/console/models/DataImportCronModel';
 5	import DataSourceModel from '@kubevirt-ui/kubevirt-api/console/models/DataSourceModel';
 6	import {
 7	  V1beta1DataImportCron,
 8	  V1beta1DataSource,
 9	} from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
10	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
11	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
12	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
13	import { deleteDVAndRelatedResources } from '@kubevirt-utils/resources/bootableresources/helpers';
14	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
15	import { kubevirtConsole } from '@kubevirt-utils/utils/utils';
16	import { k8sDelete } from '@openshift-console/dynamic-plugin-sdk';
17	import { ButtonVariant, Checkbox, Stack, StackItem } from '@patternfly/react-core';
18	
19	import useUnderlyingPVC from './hooks/useUnderlyingPVC';
20	
21	type DeleteDataSourceModalProps = {
22	  dataImportCron: V1beta1DataImportCron;
23	  dataSource: V1beta1DataSource;
24	  isOpen: boolean;
25	  onClose: () => void;
26	};
27	
28	const DeleteDataSourceModal: FC<DeleteDataSourceModalProps> = ({
29	  dataImportCron,
30	  dataSource,
31	  isOpen,
32	  onClose,
33	}) => {
34	  const { t } = useKubevirtTranslation();
35	
36	  const [deletePVC, setDeletePVC] = useState<boolean>(false);
37	  const { dv, pvc, sourceExists } = useUnderlyingPVC(dataSource);
38	
39	  const onDelete = async () => {
40	    try {
41	      await k8sDelete({
42	        model: DataImportCronModel,
43	        resource: dataImportCron,
44	      });
45	    } catch (e) {
46	      kubevirtConsole.log(e?.message);
47	    } finally {
48	      await k8sDelete({
49	        model: DataSourceModel,
50	        resource: dataSource,
51	      });
52	    }
53	
54	    if (deletePVC && sourceExists) {
55	      await deleteDVAndRelatedResources(dv, dataSource, pvc);
56	    }
57	  };
58	
59	  return (
60	    <TabModal<V1beta1DataSource>
61	      headerText={t('Delete DataSource?')}
62	      isOpen={isOpen}
63	      obj={dataSource}
64	      onClose={onClose}
65	      onSubmit={onDelete}
66	      submitBtnText={t('Delete')}
67	      submitBtnVariant={ButtonVariant.danger}
68	    >
69	      <Stack hasGutter>
70	        <StackItem>
71	          <ConfirmActionMessage obj={dataSource} />
72	        </StackItem>
73	        {sourceExists && (
74	          <StackItem>
75	            <Checkbox
76	              label={
77	                <Trans t={t}>
78	                  Delete {{ kind: pvc?.kind }} source <b>{{ name: getName(pvc) }}</b> in namespace{' '}
79	                  <b>{{ namespace: getNamespace(pvc) }}</b>
80	                </Trans>
81	              }
82	              id="delete-pvc-checkbox"
83	              isChecked={deletePVC}
84	              onChange={(_event, val) => setDeletePVC(val)}
85	            />
86	          </StackItem>
87	        )}
88	      </Stack>
89	    </TabModal>
90	  );
91	};
92	
93	export default DeleteDataSourceModal;

